// ==========================================
// PARSE & FILTER INCOMING TELEGRAM MESSAGES
// ==========================================
const update = $input.item.json;
const message = update.message;

// Skip updates with no message or no text (photos, stickers, etc.)
if (!message || !message.text) {
  return []; // Stop execution silently
}

// --- Extract core fields ---
const chatId       = String(message.chat.id);
const userId       = String(message.from?.id || '');
const username     = message.from?.username || '';
const firstName    = message.from?.first_name || 'there';
const fullName     = [message.from?.first_name, message.from?.last_name]
                       .filter(Boolean).join(' ') || 'Unknown';
const isGroup      = ['group', 'supergroup'].includes(message.chat.type);
const isPrivate    = message.chat.type === 'private';
const chatTitle    = message.chat.title || 'Private Chat';
const messageId    = message.message_id;

let text = message.text || '';

// --- Command detection ---
const isCommand  = text.startsWith('/');
const rawCommand = isCommand ? text.split(' ')[0].split('@')[0].toLowerCase() : null;

// --- Group chat gate: only respond if mentioned or a command is used ---
const BOT_USERNAME = 'QuantumBot'; // ⚙️ Change to your actual bot username (without @)
const isMentioned  = text.toLowerCase().includes(`@${BOT_USERNAME.toLowerCase()}`);
const shouldProcess = isPrivate || isCommand || isMentioned;

if (!shouldProcess) {
  return []; // Stop — unaddressed group message
}

// --- Clean bot @mention from text so AI doesn't see it ---
text = text.replace(new RegExp(`@${BOT_USERNAME}`, 'gi'), '').trim();

// --- Build the message the AI will see ---
// If user typed /book, give the AI a clear booking trigger phrase
let userMessage = text;
if (rawCommand === '/book') {
  userMessage = 'I would like to book or purchase a service from QuantumVector AI. Please help me get started.';
}

// Unique per-user session key for conversation memory
const sessionId = `qv_${chatId}_${userId}`;

return [{ json: {
  chatId,
  userId,
  username,
  firstName,
  fullName,
  text,
  userMessage,
  isGroup,
  isPrivate,
  isCommand,
  command: rawCommand,
  sessionId,
  messageId,
  chatTitle
}}];

// =============================================
// PARSE THE AI AGENT'S OUTPUT
// Detects [BOOKING_INTENT] and [ESCALATE] tags
// =============================================
const agentOutput = $input.item.json.output || '';

// Pull context from the Parse node (always available in execution chain)
const parseNode = $('🔍 Parse & Filter Message').first().json;
const chatId           = parseNode.chatId;
const firstName        = parseNode.firstName;
const fullName         = parseNode.fullName;
const username         = parseNode.username;
const sessionId        = parseNode.sessionId;
const isGroup          = parseNode.isGroup;
const chatTitle        = parseNode.chatTitle;
const originalText     = parseNode.text;

let actionType       = 'reply'; // default: just send the text
let replyText        = agentOutput;
let bookingData      = null;
let escalationReason = '';

// --- BOOKING INTENT ---
if (agentOutput.trimStart().startsWith('[BOOKING_INTENT]')) {
  actionType = 'booking';
  const lines = agentOutput.split('\n').map(l => l.trim()).filter(Boolean);
  // Find the JSON object line
  let jsonLine = lines.find(l => l.startsWith('{') && l.endsWith('}'));
  if (jsonLine) {
    try {
      bookingData = JSON.parse(jsonLine);
    } catch (e) {
      bookingData = null;
    }
  }
  // Fallback booking data from context
  if (!bookingData) {
    bookingData = {
      service: 'Service not specified',
      plan: 'Not specified',
      client_name: fullName || 'Unknown',
      contact: username ? `@${username}` : 'Not provided',
      requirements: originalText || 'General inquiry'
    };
  }
  // The reply text is everything after the JSON line
  const jsonIdx = lines.findIndex(l => l.startsWith('{') && l.endsWith('}'));
  if (jsonIdx >= 0 && jsonIdx < lines.length - 1) {
    replyText = lines.slice(jsonIdx + 1).join('\n').trim();
  } else {
    replyText = '✅ Your booking request has been received! Our team will contact you within 2 business hours.';
  }
}

// --- ESCALATION ---
else if (agentOutput.trimStart().startsWith('[ESCALATE]')) {
  actionType = 'escalate';
  const lines = agentOutput.split('\n').map(l => l.trim()).filter(Boolean);
  // Line 1 after tag is the reason
  escalationReason = lines[1] || 'Complex request requiring human attention';
  // Everything after reason is the user message
  replyText = lines.slice(2).join('\n').trim()
    || '🤝 A specialist from our team will reach out to you shortly! You can also email quantumvectorllc@gmail.com for a faster response.';
}

// Timestamp in EAT (UTC+3)
const now = new Date();
const eatTime = new Intl.DateTimeFormat('en-KE', {
  dateStyle: 'medium',
  timeStyle: 'short',
  timeZone: 'Africa/Nairobi'
}).format(now);

return [{ json: {
  actionType,
  replyText,
  bookingData,
  escalationReason,
  chatId,
  firstName,
  fullName,
  username,
  sessionId,
  isGroup,
  chatTitle,
  originalText,
  eatTime
}}];

